import React from 'react';
import { FiPackage, FiTruck, FiBox, FiGlobe, FiBriefcase, FiSearch, FiCpu } from 'react-icons/fi';

const ServiceCard = ({ icon, title, desc, btnColor }) => (
  <div className="col">
    <div className="premium-card h-100 border-0 shadow-lg text-center p-4 rounded-4" 
         style={{ 
           background: 'rgba(255, 255, 255, 0.85)', 
           backdropFilter: 'blur(10px)',
           transition: 'all 0.4s ease-in-out',
           border: '1px solid rgba(255, 255, 255, 0.3)'
         }}>
      <div className="mb-3 d-flex justify-content-center icon-wrapper" 
           style={{ 
             fontSize: '3rem', 
             color: btnColor,
             filter: 'drop-shadow(0px 4px 6px rgba(0,0,0,0.1))' 
           }}>
        {icon}
      </div>
      <h6 className="fw-bold mb-2 text-dark" style={{ letterSpacing: '0.5px' }}>{title}</h6>
      <p className="text-muted mb-4" style={{ fontSize: '12px', lineHeight: '1.5' }}>{desc}</p>
      <button className="btn btn-sm w-100 rounded-pill text-white fw-bold py-2 shadow-sm transition-btn" 
              style={{ backgroundColor: btnColor, border: 'none' }}>
        Book Now
      </button>
    </div>
  </div>
);

const Home = () => {
  return (
    <div className="container py-5 mt-4">
      {/* Premium Hero Section */}
      <div className="text-center mb-5 animate-fade-in">
        <h1 className="fw-extrabold text-dark display-4 mb-2" style={{ letterSpacing: '-1px' }}>
          Logistics Aggregator Platform
        </h1>
        <div className="d-flex justify-content-center align-items-center gap-2">
          <div style={{ height: '2px', width: '50px', backgroundColor: '#0056b3' }}></div>
          <h5 className="text-primary fw-bold m-0 text-uppercase tracking-widest" style={{ fontSize: '14px' }}>
            One Solution for All Deliveries
          </h5>
          <div style={{ height: '2px', width: '50px', backgroundColor: '#0056b3' }}></div>
        </div>
      </div>

      {/* Grid of Cards */}
      <div className="row row-cols-1 row-cols-md-2 row-cols-lg-4 row-cols-xl-7 g-4 justify-content-center">
        <ServiceCard icon={<FiPackage />} title="Courier" desc="Express & Domestic Delivery" btnColor="#27ae60" />
        <ServiceCard icon={<FiTruck />} title="Transport" desc="Heavy Haulage Solutions" btnColor="#d35400" />
        <ServiceCard icon={<FiBox />} title="Packers" desc="Safe Home Shifting" btnColor="#f39c12" />
        <ServiceCard icon={<FiGlobe />} title="Global" desc="Air & Sea Freight" btnColor="#8e44ad" />
        <ServiceCard icon={<FiBriefcase />} title="MSME" desc="Bulk Business Logistics" btnColor="#2980b9" />
        <ServiceCard icon={<FiSearch />} title="Tracking" desc="Real-time Order Tracking" btnColor="#7f8c8d" />
        <ServiceCard icon={<FiCpu />} title="AI Assist" desc="Smart AI Logistics" btnColor="#2c3e50" />
      </div>

      {/* Quick Check Section with Glass Effect */}
      <div className="mt-5 p-5 rounded-5 shadow-lg border-0 text-white d-flex justify-content-between align-items-center" 
           style={{ 
             background: 'linear-gradient(135deg, #0056b3 0%, #003d7a 100%)',
           }}>
        <div>
          <h3 className="fw-bold m-0">Quick Price Check</h3>
          <p className="m-0 text-white-50">Get instant quotes for your shipment</p>
        </div>
        <button className="btn btn-warning btn-lg rounded-pill px-5 fw-bold shadow">Check Now</button>
      </div>

      {/* Custom CSS for Animations */}
      <style>{`
        .premium-card:hover {
          transform: translateY(-15px);
          background: rgba(255, 255, 255, 1) !important;
          box-shadow: 0 20px 40px rgba(0,0,0,0.15) !important;
        }
        .transition-btn:hover {
          opacity: 0.9;
          transform: scale(1.05);
        }
        .fw-extrabold { font-weight: 800; }
      `}</style>
    </div>
  );
};

export default Home;
